public record DragonBreathVfxPayload(int shooterId, double eyeX, double eyeY, double eyeZ, double lookX, double lookY, double lookZ) implements CustomPacketPayload {
    public static final CustomPacketPayload.Type<DragonBreathVfxPayload> TYPE =
        new CustomPacketPayload.Type<>(ResourceLocation.fromNamespaceAndPath("adminspec", "dragon_breath_vfx"));
    public static final StreamCodec<FriendlyByteBuf, DragonBreathVfxPayload> STREAM_CODEC = new StreamCodec<>() {
        public DragonBreathVfxPayload decode(FriendlyByteBuf buf) { return new DragonBreathVfxPayload(buf.readVarInt(), buf.readDouble(), buf.readDouble(), buf.readDouble(), buf.readDouble(), buf.readDouble(), buf.readDouble()); }
        public void encode(FriendlyByteBuf buf, DragonBreathVfxPayload p) { buf.writeVarInt(p.shooterId()); buf.writeDouble(p.eyeX()); buf.writeDouble(p.eyeY()); buf.writeDouble(p.eyeZ()); buf.writeDouble(p.lookX()); buf.writeDouble(p.lookY()); buf.writeDouble(p.lookZ()); }
    };
    public Type<? extends CustomPacketPayload> type() { return TYPE; }
    public static void handle(DragonBreathVfxPayload payload, IPayloadContext ctx) {
        if (FMLEnvironment.dist != Dist.CLIENT) return;
        ctx.enqueueWork(() -> ClientHandler.spawnBreathVfx(payload));
    }
    public static final class ClientHandler {
        public static void spawnBreathVfx(DragonBreathVfxPayload p) {
            Minecraft mc = Minecraft.getInstance(); ClientLevel level = mc.level; if (level == null) return;
            Vec3 eye = new Vec3(p.eyeX(), p.eyeY(), p.eyeZ()); Vec3 look = new Vec3(p.lookX(), p.lookY(), p.lookZ());
            for (double d = 0.3; d < 16.0; d += 0.35) {
                Vec3 pos = eye.add(look.scale(d)); double spread = d * 0.06;
                level.addParticle(ParticleTypes.CRIT, pos.x + (Math.random()-0.5)*spread, pos.y + (Math.random()-0.5)*spread, pos.z + (Math.random()-0.5)*spread, look.x*0.3, look.y*0.3, look.z*0.3);
                level.addParticle(ParticleTypes.ENCHANTED_HIT, pos.x + (Math.random()-0.5)*spread*1.5, pos.y + (Math.random()-0.5)*spread*1.5, pos.z + (Math.random()-0.5)*spread*1.5, (Math.random()-0.5)*0.1, (Math.random()-0.5)*0.1, (Math.random()-0.5)*0.1);
                if (d % 1.0 < 0.35) level.addParticle(ParticleTypes.SWEEP_ATTACK, pos.x, pos.y, pos.z, 0, 0, 0);
                if (d % 2.0 < 0.35) level.addParticle(ParticleTypes.ELECTRIC_SPARK, pos.x + (Math.random()-0.5)*spread*2, pos.y + (Math.random()-0.5)*spread*2, pos.z + (Math.random()-0.5)*spread*2, (Math.random()-0.5)*0.2, (Math.random()-0.5)*0.2, (Math.random()-0.5)*0.2);
            }
            Vec3 tip = eye.add(look.scale(16.0));
            for (int i = 0; i < 12; i++) level.addParticle(ParticleTypes.EXPLOSION, tip.x + (Math.random()-0.5)*2.0, tip.y + (Math.random()-0.5)*2.0, tip.z + (Math.random()-0.5)*2.0, 0, 0, 0);
            level.addParticle(ParticleTypes.FLASH, tip.x, tip.y, tip.z, 0, 0, 0);
        }
    }
}
